const EXEMPTION_SINGLE = 13610000;
const brackets = [[0,10000,.18,0],[10000,20000,.20,1800],[20000,40000,.22,3800],[40000,60000,.24,8200],[60000,80000,.26,13000],[80000,100000,.28,18200],[100000,150000,.30,23800],[150000,250000,.32,38800],[250000,500000,.34,70800],[500000,750000,.37,155800],[750000,1000000,.39,248300],[1000000,Infinity,.40,345800]] as const;
const money = (v: number, d = 0) => formatCurrencyValue(v, { maximumFractionDigits: d });
function estateTax(taxable: number) { const b = [...brackets].reverse().find(([min]) => taxable > min) || brackets[0]; return taxable > 0 ? b[3] + (taxable - b[0]) * b[2] : 0; }

